def scalar_strings(value: Any) -> list[str]:
    if isinstance(value, str):
        return [value]
    if isinstance(value, dict):
        result: list[str] = []
        for item in value.values():
            result.extend(scalar_strings(item))
        return result
    if isinstance(value, list):
        result = []
        for item in value:
            result.extend(scalar_strings(item))
        return result
    return []


